mapper.select:
SELECT a.spot_id AS spotId, a.forecast_id AS forecastId, s.experience, s.name AS spotName, mf.forecast_date AS forecastDate, mf.time_slot AS timeSlot, mf.total_index AS totalIndex, a.recommended, a.recommendation_reason AS recommendationReason, a.source_forecast_updated_at AS sourceForecastUpdatedAt, a.generated_at AS generatedAt FROM ai_spot_analyses a JOIN spots s ON s.id = a.spot_id JOIN marine_forecasts mf ON mf.id = a.forecast_id WHERE a.forecast_id IN
#{forecastId}
AND a.source_forecast_updated_at = mf.updated_at
